parameters.query:
NTANetAnalytics
| where SubType == 'FlowLog' and FaSchemaVersion == '3'
// 1. Combine both columns into a single dynamic array pack
| extend Subscriptions = pack_array(SrcSubscription, DestSubscription)
// 2. Expand the array into individual rows
| mv-expand Subscriptions to typeof(string)
// 3. Filter out any empty or null values
| where isnotempty(Subscriptions)
| distinct Subscriptions
